<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1">
<title>Personal Expense Tracker</title>
<style>
  * { box-sizing: border-box; }
  body {
    font-family: system-ui, -apple-system, "Segoe UI", sans-serif;
    background: #f4f5f7;
    color: #222;
    margin: 0;
    padding: 1.5rem;
  }
  .wrap { max-width: 720px; margin: 0 auto; }
  h1 { font-size: 1.4rem; margin: 0 0 1rem; }
  h2 { font-size: 1.05rem; margin: 1.5rem 0 .5rem; }
  fieldset {
    border: 1px solid #ccc;
    border-radius: 8px;
    background: #fff;
    padding: 1rem;
    margin: 0 0 1rem;
  }
  legend { font-weight: 600; padding: 0 .4rem; }
  .row { display: flex; flex-wrap: wrap; gap: .75rem; align-items: flex-end; }
  .field { display: flex; flex-direction: column; gap: .25rem; }
  label { font-size: .8rem; font-weight: 600; color: #444; }
  input, select, button {
    font: inherit;
    padding: .4rem .5rem;
    border: 1px solid #bbb;
    border-radius: 6px;
    background: #fff;
  }
  input:focus, select:focus { outline: 2px solid #4a7dcf; outline-offset: 1px; }
  button { cursor: pointer; }
  #add-expense {
    background: #2f6fce;
    color: #fff;
    border-color: #2f6fce;
    font-weight: 600;
    padding: .45rem 1rem;
  }
  #add-expense:hover { background: #275db0; }
  #form-error {
    color: #b3261e;
    font-size: .9rem;
    min-height: 1.2em;
    margin-top: .5rem;
  }
  .summary-bar {
    display: flex;
    flex-wrap: wrap;
    gap: .5rem 1rem;
    align-items: baseline;
    background: #fff;
    border: 1px solid #ccc;
    border-radius: 8px;
    padding: .75rem 1rem;
    margin-bottom: 1rem;
  }
  .total-label { font-weight: 600; }
  #total { font-size: 1.3rem; font-weight: 700; }
  .cat-total {
    font-size: .85rem;
    background: #eef2f9;
    border: 1px solid #d4ddec;
    border-radius: 999px;
    padding: .15rem .6rem;
  }
  ul#expense-list { list-style: none; margin: 0; padding: 0; }
  .expense {
    display: flex;
    align-items: center;
    gap: .75rem;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 8px;
    padding: .55rem .75rem;
    margin-bottom: .4rem;
  }
  .exp-amount { font-weight: 700; min-width: 5.5rem; }
  .exp-cat {
    font-size: .8rem;
    background: #e8eef8;
    border-radius: 999px;
    padding: .1rem .55rem;
    text-transform: capitalize;
  }
  .exp-date { font-size: .85rem; color: #555; }
  .exp-note { font-size: .85rem; color: #666; flex: 1; overflow-wrap: anywhere; }
  .exp-del {
    margin-left: auto;
    background: #fbe9e7;
    border: 1px solid #e3b6b1;
    color: #a1352b;
    border-radius: 6px;
    padding: .2rem .55rem;
  }
  .exp-del:hover { background: #f5d3ce; }
  .empty-msg { color: #777; font-style: italic; padding: .5rem 0; }
</style>
</head>
<body>
<div class="wrap">
  <h1>Personal Expense Tracker</h1>

  <form id="expense-form" novalidate>
    <fieldset>
      <legend>Add expense</legend>
      <div class="row">
        <div class="field">
          <label for="amount">Amount</label>
          <input type="number" id="amount" step="0.01" min="0" placeholder="0.00">
        </div>
        <div class="field">
          <label for="category">Category</label>
          <select id="category">
            <option value="groceries">groceries</option>
            <option value="transport">transport</option>
            <option value="bills">bills</option>
            <option value="fun">fun</option>
          </select>
        </div>
        <div class="field">
          <label for="date">Date</label>
          <input type="date" id="date">
        </div>
        <div class="field">
          <label for="note">Note (optional)</label>
          <input type="text" id="note" placeholder="e.g. weekly shop">
        </div>
        <button type="submit" id="add-expense">Add expense</button>
      </div>
      <div id="form-error" role="alert" aria-live="polite"></div>
    </fieldset>
  </form>

  <fieldset>
    <legend>Filters</legend>
    <div class="row">
      <div class="field">
        <label for="filter-category">Category</label>
        <select id="filter-category">
          <option value="all">all</option>
          <option value="groceries">groceries</option>
          <option value="transport">transport</option>
          <option value="bills">bills</option>
          <option value="fun">fun</option>
        </select>
      </div>
      <div class="field">
        <label for="filter-from">From</label>
        <input type="date" id="filter-from">
      </div>
      <div class="field">
        <label for="filter-to">To</label>
        <input type="date" id="filter-to">
      </div>
      <button type="button" id="clear-filters">Clear filters</button>
    </div>
  </fieldset>

  <div class="summary-bar">
    <span class="total-label">Visible total:</span>
    <span id="total">0.00</span>
    <span id="cat-summary" style="display:contents"></span>
  </div>

  <h2>Expenses</h2>
  <ul id="expense-list"></ul>
  <div id="empty-msg" class="empty-msg" hidden>No expenses to show.</div>
</div>

<script>
(function () {
  'use strict';

  var STORAGE_KEY = 'expense-tracker-expenses';
  var CATEGORIES = ['groceries', 'transport', 'bills', 'fun'];

  var amountEl = document.getElementById('amount');
  var categoryEl = document.getElementById('category');
  var dateEl = document.getElementById('date');
  var noteEl = document.getElementById('note');
  var formEl = document.getElementById('expense-form');
  var errorEl = document.getElementById('form-error');
  var listEl = document.getElementById('expense-list');
  var totalEl = document.getElementById('total');
  var catSummaryEl = document.getElementById('cat-summary');
  var filterCatEl = document.getElementById('filter-category');
  var filterFromEl = document.getElementById('filter-from');
  var filterToEl = document.getElementById('filter-to');
  var clearFiltersEl = document.getElementById('clear-filters');
  var emptyMsgEl = document.getElementById('empty-msg');

  var expenses = loadExpenses();

  function loadExpenses() {
    try {
      var raw = localStorage.getItem(STORAGE_KEY);
      if (!raw) return [];
      var parsed = JSON.parse(raw);
      if (!Array.isArray(parsed)) return [];
      return parsed.filter(function (e) {
        return e && typeof e.amount === 'number' && isFinite(e.amount) &&
               typeof e.category === 'string' && typeof e.date === 'string';
      });
    } catch (err) {
      return [];
    }
  }

  function saveExpenses() {
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(expenses));
    } catch (err) {
      /* storage unavailable — app still works for the session */
    }
  }

  function matchesFilters(exp) {
    var cat = filterCatEl.value;
    if (cat !== 'all' && exp.category !== cat) return false;
    var from = filterFromEl.value;
    var to = filterToEl.value;
    if (from && exp.date < from) return false;
    if (to && exp.date > to) return false;
    return true;
  }

  function render() {
    listEl.textContent = '';

    // newest first: by date desc, then insertion order (most recent added first)
    var sorted = expenses.slice().sort(function (a, b) {
      if (a.date !== b.date) return a.date < b.date ? 1 : -1;
      return b.id - a.id;
    });

    var visibleTotal = 0;
    var catTotals = {};
    CATEGORIES.forEach(function (c) { catTotals[c] = 0; });
    var visibleCount = 0;

    sorted.forEach(function (exp) {
      var li = document.createElement('li');
      li.className = 'expense';
      li.dataset.id = exp.id;

      var amountSpan = document.createElement('span');
      amountSpan.className = 'exp-amount';
      amountSpan.textContent = exp.amount.toFixed(2);

      var catSpan = document.createElement('span');
      catSpan.className = 'exp-cat';
      catSpan.textContent = exp.category;

      var dateSpan = document.createElement('span');
      dateSpan.className = 'exp-date';
      dateSpan.textContent = exp.date;

      var noteSpan = document.createElement('span');
      noteSpan.className = 'exp-note';
      noteSpan.textContent = exp.note || '';

      var delBtn = document.createElement('button');
      delBtn.type = 'button';
      delBtn.className = 'exp-del';
      delBtn.textContent = 'Delete';
      delBtn.setAttribute('aria-label', 'Delete expense of ' + exp.amount.toFixed(2));

      li.appendChild(amountSpan);
      li.appendChild(catSpan);
      li.appendChild(dateSpan);
      li.appendChild(noteSpan);
      li.appendChild(delBtn);

      if (matchesFilters(exp)) {
        visibleTotal += exp.amount;
        if (!(exp.category in catTotals)) catTotals[exp.category] = 0;
        catTotals[exp.category] += exp.amount;
        visibleCount++;
      } else {
        li.style.display = 'none';
        li.hidden = true;
      }

      listEl.appendChild(li);
    });

    totalEl.textContent = visibleTotal.toFixed(2);

    catSummaryEl.textContent = '';
    Object.keys(catTotals).forEach(function (cat) {
      var chip = document.createElement('span');
      chip.className = 'cat-total';
      chip.setAttribute('data-cat', cat);
      chip.textContent = cat + ': ' + catTotals[cat].toFixed(2);
      catSummaryEl.appendChild(chip);
    });

    emptyMsgEl.hidden = visibleCount > 0;
  }

  formEl.addEventListener('submit', function (ev) {
    ev.preventDefault();

    var rawAmount = amountEl.value.trim();
    var amount = parseFloat(rawAmount);
    var date = dateEl.value;

    if (rawAmount === '' || isNaN(amount) || !isFinite(amount)) {
      errorEl.textContent = 'Please enter a valid numeric amount.';
      return;
    }
    if (amount <= 0) {
      errorEl.textContent = 'Amount must be greater than zero.';
      return;
    }
    if (!date) {
      errorEl.textContent = 'Please pick a date for the expense.';
      return;
    }

    expenses.push({
      id: expenses.length ? Math.max.apply(null, expenses.map(function (e) { return e.id || 0; })) + 1 : 1,
      amount: Math.round(amount * 100) / 100,
      category: categoryEl.value,
      date: date,
      note: noteEl.value.trim()
    });

    saveExpenses();
    errorEl.textContent = '';
    amountEl.value = '';
    noteEl.value = '';
    render();
    amountEl.focus();
  });

  listEl.addEventListener('click', function (ev) {
    var btn = ev.target.closest('.exp-del');
    if (!btn) return;
    var li = btn.closest('.expense');
    var id = Number(li.dataset.id);
    expenses = expenses.filter(function (e) { return e.id !== id; });
    saveExpenses();
    render();
  });

  filterCatEl.addEventListener('change', render);
  filterFromEl.addEventListener('change', render);
  filterFromEl.addEventListener('input', render);
  filterToEl.addEventListener('change', render);
  filterToEl.addEventListener('input', render);

  clearFiltersEl.addEventListener('click', function () {
    filterCatEl.value = 'all';
    filterFromEl.value = '';
    filterToEl.value = '';
    render();
  });

  render();
})();
</script>
</body>
</html>
